const today = new Date();
today.setHours(0, 0, 0, 0);

const todayLeads = items.filter(item => {
  const ts = new Date(item.json.Timestamp);
  return ts >= today;
});

const total = todayLeads.length;
const gradeA = todayLeads.filter(i => i.json.Grade === 'A').length;
const gradeB = todayLeads.filter(i => i.json.Grade === 'B').length;
const gradeC = todayLeads.filter(i => i.json.Grade === 'C').length;

const sources = {};
todayLeads.forEach(i => {
  const s = i.json.Source || 'unknown';
  sources[s] = (sources[s] || 0) + 1;
});

const sourceRows = Object.entries(sources)
  .sort((a,b) => b[1]-a[1])
  .map(([s,c]) => `<tr><td style='padding:5px 12px'>${s}</td><td style='padding:5px 12px;text-align:center'>${c}</td></tr>`)
  .join('');

const leadRows = todayLeads.map(i => {
  const gradeColor = i.json.Grade === 'A' ? '#d4edda' : i.json.Grade === 'B' ? '#fff3cd' : '#f8d7da';
  return `<tr style='background:${gradeColor}'>
    <td style='padding:5px 10px'>${i.json.Name}</td>
    <td style='padding:5px 10px'>${i.json.Email}</td>
    <td style='padding:5px 10px'>${i.json.Source}</td>
    <td style='padding:5px 10px;text-align:center'><b>${i.json.Grade}</b></td>
    <td style='padding:5px 10px;font-size:12px'>${i.json.Reason}</td>
  </tr>`;
}).join('');

const dateStr = new Date().toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

const html = `
<div style='font-family:Arial,sans-serif;max-width:700px'>
  <h2 style='color:#1a1a2e'>Lead Summary — ${dateStr}</h2>
  <div style='display:flex;gap:16px;margin-bottom:24px'>
    <div style='background:#f0f4ff;padding:16px 24px;border-radius:8px;text-align:center'>
      <div style='font-size:28px;font-weight:bold'>${total}</div>
      <div style='color:#666;font-size:13px'>Total leads</div>
    </div>
    <div style='background:#d4edda;padding:16px 24px;border-radius:8px;text-align:center'>
      <div style='font-size:28px;font-weight:bold;color:#155724'>${gradeA}</div>
      <div style='color:#155724;font-size:13px'>Grade A (hot)</div>
    </div>
    <div style='background:#fff3cd;padding:16px 24px;border-radius:8px;text-align:center'>
      <div style='font-size:28px;font-weight:bold;color:#856404'>${gradeB}</div>
      <div style='color:#856404;font-size:13px'>Grade B (warm)</div>
    </div>
    <div style='background:#f8d7da;padding:16px 24px;border-radius:8px;text-align:center'>
      <div style='font-size:28px;font-weight:bold;color:#721c24'>${gradeC}</div>
      <div style='color:#721c24;font-size:13px'>Grade C (cold)</div>
    </div>
  </div>

  <h3>By source</h3>
  <table style='border-collapse:collapse;width:100%;margin-bottom:24px'>
    <tr style='background:#eee'><th style='padding:6px 12px;text-align:left'>Source</th><th style='padding:6px 12px'>Count</th></tr>
    ${sourceRows || '<tr><td colspan=2 style="padding:8px 12px;color:#999">No leads today</td></tr>'}
  </table>

  <h3>All leads today</h3>
  <table style='border-collapse:collapse;width:100%;font-size:13px'>
    <tr style='background:#333;color:#fff'>
      <th style='padding:6px 10px;text-align:left'>Name</th>
      <th style='padding:6px 10px;text-align:left'>Email</th>
      <th style='padding:6px 10px;text-align:left'>Source</th>
      <th style='padding:6px 10px'>Grade</th>
      <th style='padding:6px 10px;text-align:left'>AI Reason</th>
    </tr>
    ${leadRows || '<tr><td colspan=5 style="padding:10px;color:#999">No leads today</td></tr>'}
  </table>
</div>`;

return [{ json: { html, total, gradeA, gradeB, gradeC, dateStr } }];
